return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2;','language'=>'bel','pot-creation-date'=>'2026-05-26 15:47+0200','po-revision-date'=>'2026-05-26 15:47+0200','translation-revision-date'=>'2026-05-26 15:47+0200','project-id-version'=>'Transliterator','x-generator'=>'Poedit 3.9','messages'=>['Block Editor: Script selector' . "\4" . 'Latin'=>'Лацініца','Block Editor: Script selector' . "\4" . 'Cyrillic'=>'Кірыліца','Block Editor: Script selector' . "\4" . 'Choose your display type:'=>'Выберыце тып адлюстравання:','Block Editor: Script selector' . "\4" . 'Script Selector'=>'Пераключальнік пісьма','Block Editor: Script selector' . "\4" . 'Inline'=>'Убудаваны','Block Editor: Script selector' . "\4" . 'Select'=>'Выбар','Block Editor: Script selector' . "\4" . 'List'=>'Спіс','Block Editor: Script selector' . "\4" . 'List items'=>'Элементы спісу','Block Editor: Script selector' . "\4" . 'Separator:'=>'Раздзяляльнік:','Block Editor: Script selector' . "\4" . 'Cyrillic caption:'=>'Подпіс для кірыліцы:','Block Editor: Script selector' . "\4" . 'Latin Caption:'=>'Подпіс для лацініцы:','undefined'=>'не вызначана','Freelance Jobs - Find or post freelance jobs'=>'Фрыланс-вакансіі — знайдзіце працу або размясціце вакансіі для фрылансераў','Contra Team - A complete hosting solution in one place'=>'Contra Team — поўнае рашэнне для хостынгу ў адным месцы','Transliteration'=>'Транслітарацыя','Latin'=>'Лацініца','Cyrillic'=>'Кірыліца','Help'=>'Даведка','To insert language script selector just add a relative link after the link\'s keyword, example :'=>'Каб уставіць пераключальнік пісьма, проста дадайце адносную спасылку пасля ключавога слова спасылкі, напрыклад:','You can also use'=>'Вы таксама можаце выкарыстоўваць','for change to Latin or use'=>'для пераключэння на лацініцу або выкарыстоўвайце','for change to Cyrillic'=>'для пераключэння на кірыліцу','Add to Menu'=>'Дадаць у меню','The name of this navigation is written by always putting the Latin name first, then the Cyrillic one second, separated by the sign %s'=>'Назва гэтага пункта навігацыі заўсёды запісваецца так: спачатку лацінская назва, потым кірылічная, падзеленая знакам %s','Example: Latinica | Ћирилица'=>'Прыклад: Лацініца | Кірыліца','Note that the white space around them will be cleared.'=>'Звярніце ўвагу, што прабелы вакол іх будуць выдалены.','You have been using <b> %1$s </b> plugin for a while. We hope you liked it!'=>'Вы ўжо некаторы час карыстаецеся плагінам <b> %1$s </b>. Спадзяёмся, ён вам спадабаўся!','Please give us a quick rating, it works as a boost for us to keep working on the plugin!'=>'Калі ласка, хутка ацаніце нас, гэта стане для нас выдатнай падтрымкай і дапаможа далей працаваць над плагінам!','Rate Now!'=>'Ацаніць зараз!','I\'ve already done that!'=>'Я ўжо гэта зрабіў!','Hey there! It\'s been a while since you\'ve been using the <b> %1$s </b> plugin'=>'Прывітанне! Вы ўжо некаторы час карыстаецеся плагінам <b> %1$s </b>','I\'m glad to hear you\'re enjoying the plugin. I\'ve put a lot of time and effort into ensuring that your website runs smoothly. If you\'re feeling generous, how about %s for my hard work? 😊'=>'Рады чуць, што вам падабаецца гэты плагін. Я ўклаў шмат часу і намаганняў, каб ваш сайт працаваў без збояў. Калі хочаце аддзячыць мне, як наконт %s за маю працу? 😊','treating me to a coffee'=>'пачаставаць мяне кавай','Or simply %s forever.'=>'Або проста %s назаўсёды.','hide this message'=>'схаваць гэта паведамленне','Hey there! It\'s been a while since you\'ve been using the <b>%1$s</b> plugin'=>'Прывітанне! Вы ўжо некаторы час карыстаецеся плагінам <b>%1$s</b>','I\'m really happy to see this plugin being useful for your website. If you ever feel like giving back, here\'s one way to do it.'=>'Мне вельмі прыемна бачыць, што гэты плагін карысны для вашага сайта. Калі вы захочаце аддзячыць, вось адзін са спосабаў гэта зрабіць.','Bank account (Banca Intesa a.d. Beograd):'=>'Банкаўскі рахунак (Banca Intesa a.d. Beograd):','Every little bit helps, and I truly appreciate it! ❤️'=>'Любая дапамога важная, і я шчыра гэта цаню! ❤️','Find Work or %1$s in Serbia, Bosnia, Croatia, and Beyond!'=>'Знайдзіце працу або %1$s у Сербіі, Босніі, Харватыі і за іх межамі!','Visit %2$s to connect with skilled professionals across the region. Whether you need a project completed or are looking for work, our platform is your gateway to successful collaboration.'=>'Наведайце %2$s, каб звязацца з кваліфікаванымі спецыялістамі па ўсім рэгіёне. Незалежна ад таго, патрэбен вам выканаўца для праекта ці вы шукаеце працу, наша платформа стане вашым шляхам да паспяховага супрацоўніцтва.','Hire Top Freelancers'=>'Найміце лепшых фрылансераў','Freelance Jobs'=>'Фрыланс-вакансіі','Join us today!'=>'Далучайцеся да нас ужо сёння!','This plugin uses cookies and should be listed in your Privacy Policy page to prevent privacy issues.'=>'Гэты плагін выкарыстоўвае cookie-файлы і павінен быць пазначаны на старонцы вашай палітыкі прыватнасці, каб пазбегнуць праблем з прыватнасцю.','Suggested text:'=>'Рэкамендаваны тэкст:','This website uses the %1$s plugin to transliterate content.'=>'Гэты сайт выкарыстоўвае плагін %1$s для транслітарацыі змесціва.','This is a simple and easy add-on with which this website translates content from Cyrillic to Latin and vice versa. This transliteration plugin also supports special shortcodes and functions that use cookies to specify the language script.'=>'Гэта простае і зручнае дадатак, з дапамогай якога гэты сайт перакладае змесціва з кірыліцы на лацініцу і наадварот. Гэты плагін транслітарацыі таксама падтрымлівае спецыяльныя шорткоды і функцыі, што выкарыстоўваюць cookie для вызначэння пісьма мовы.','These cookies do not affect your privacy because they are not intended for tracking and analytics. These cookies can have only two values: "%1$s" or "%2$s".'=>'Гэтыя cookie не ўплываюць на вашу прыватнасць, бо не прызначаныя для адсочвання і аналітыкі. Гэтыя cookie могуць мець толькі два значэнні: \\"%1$s\\" або \\"%2$s\\".','Important upgrade notice for the version %s:'=>'Важнае паведамленне пра абнаўленне для версіі %s:','NOTE: Before doing the update, it would be a good idea to backup your WordPress installations and settings.'=>'ЗАЎВАГА: Перад абнаўленнем рэкамендуецца зрабіць рэзервовую копію вашых усталёвак і налад WordPress.','The %1$s cannot run on PHP versions older than PHP %2$s. Please contact your host and ask them to upgrade.'=>'%1$s не можа працаваць на версіях PHP старэйшых за PHP %2$s. Звяжыцеся з вашым хостынг-правайдэрам і папрасіце абнавіць PHP.','Transliteration plugin requires attention:'=>'Плагін транслітарацыі патрабуе ўвагі:','Your plugin works under Only WooCoomerce mode and you need to %s because WooCommerce is no longer active.'=>'Ваш плагін працуе ў рэжыме Only WooCoomerce, і вам трэба %s, бо WooCommerce больш не актыўны.','update your settings'=>'абнавіць налады','Transliteration plugin requires a Multibyte String PHP extension (mbstring).'=>'Плагіну транслітарацыі патрабуецца PHP-пашырэнне Multibyte String (mbstring).','Without %s you will not be able to use this plugin.'=>'Без %s вы не зможаце выкарыстоўваць гэты плагін.','Multibyte String Installation'=>'Усталяванне Multibyte String','this PHP extension'=>'гэта PHP-пашырэнне','The %1$s cannot run on WordPress versions older than %2$s. Please update your WordPress installation.'=>'%1$s не можа працаваць на версіях WordPress старэйшых за %2$s. Калі ласка, абнавіце вашу ўсталёўку WordPress.','Global Settings'=>'Глабальныя налады','My site is'=>'Мой сайт','Transliteration Mode'=>'Рэжым транслітарацыі','First visit mode'=>'Рэжым першага наведвання','Language scheme'=>'Моўная схема','Plugin Mode'=>'Рэжым плагіна','Force transliteration permalinks to latin'=>'Прымусова транслітараваць пастаянныя спасылкі ў лацініцу','Filters'=>'Фільтры','Transliteration Filters'=>'Фільтры транслітарацыі','Exclude Latin words that you do not want to be transliterated to the Cyrillic.'=>'Выключыце лацінскія словы, якія не трэба транслітараваць у кірыліцу.','Exclude Cyrillic words that you do not want to be transliterated to the Latin.'=>'Выключыце кірылічныя словы, якія не трэба транслітараваць у лацініцу.','Special Settings'=>'Спецыяльныя налады','Enable cache support'=>'Уключыць падтрымку кэша','Force widget transliteration'=>'Прымусовая транслітарацыя віджэтаў','Force e-mail transliteration'=>'Прымусовая транслітарацыя электроннай пошты','Force transliteration for WordPress REST API'=>'Прымусовая транслітарацыя для WordPress REST API','Force transliteration for AJAX calls'=>'Прымусовая транслітарацыя для AJAX-запытаў','EXPERIMENTAL'=>'ЭКСПЕРЫМЕНТАЛЬНА','JavaScript Dynamic Transliteration'=>'Дынамічная транслітарацыя JavaScript','WP Admin'=>'WP Admin','WP-Admin transliteration'=>'Транслітарацыя WP-Admin','Allow Cyrillic Usernames'=>'Дазволіць кірылічныя імёны карыстальнікаў','Allow Admin Tools'=>'Дазволіць інструменты адміністратара','Media Settings'=>'Налады медыя','Transliterate filenames to latin'=>'Транслітараваць імёны файлаў у лацініцу','Filename delimiter'=>'Раздзяляльнік імя файла','WordPress Search'=>'Пошук WordPress','Enable search transliteration'=>'Уключыць транслітарацыю пошуку','Fix Diacritics'=>'Выправіць дыякрытычныя знакі','Search Mode'=>'Рэжым пошуку','SEO Settings'=>'Налады SEO','Parameter URL selector'=>'Селектар параметра URL','RSS transliteration'=>'Транслітарацыя RSS','Exclusion'=>'Выключэнне','Language: %s'=>'Мова: %s','Misc.'=>'Рознае','Enable body class'=>'Уключыць клас body','Theme Support'=>'Падтрымка тэмы','Support the Project'=>'Падтрымайце праект','Contributors & Developers'=>'Удзельнікі і распрацоўшчыкі','This setting determines the mode of operation for the Transliteration plugin.'=>'Гэты параметр вызначае рэжым працы плагіна транслітарацыі.','Carefully choose the option that is best for your site and the plugin will automatically set everything you need for optimal performance.'=>'Уважліва выберыце варыянт, які найлепш падыходзіць вашаму сайту, і плагін аўтаматычна наладзіць усё неабходнае для аптымальнай працы.','This section contains filters for exclusions, allowing you to specify content that should be excluded from transliteration, and also includes a filter to disable certain WordPress filters related to transliteration.'=>'Гэты раздзел утрымлівае фільтры выключэнняў, якія дазваляюць пазначыць змесціва, якое трэба выключыць з транслітарацыі, а таксама фільтр для адключэння некаторых фільтраў WordPress, звязаных з транслітарацыяй.','These are special settings that can enhance transliteration and are used only if you need them.'=>'Гэта спецыяльныя налады, якія могуць палепшыць транслітарацыю і выкарыстоўваюцца толькі пры неабходнасці.','These settings apply to the administrative part.'=>'Гэтыя налады прымяняюцца да адміністрацыйнай часткі.','Upload, view and control media and files.'=>'Загрузка, прагляд і кіраванне медыя і файламі.','Our plugin also has special SEO options that are very important for your project.'=>'Наш плагін таксама мае спецыяльныя SEO-налады, якія вельмі важныя для вашага праекта.','Within this configuration section, you have the opportunity to customize your experience by selecting the particular languages for which you wish to turn off the transliteration function. This feature is designed to give you greater control and adaptability over how the system handles transliteration, allowing you to disable it for specific languages based on your individual needs or preferences.'=>'У гэтым раздзеле канфігурацыі вы можаце наладзіць працу сістэмы, выбраўшы канкрэтныя мовы, для якіх хочаце адключыць функцыю транслітарацыі. Гэта магчымасць дае вам больш кантролю і гнуткасці над тым, як сістэма апрацоўвае транслітарацыю, дазваляючы адключаць яе для асобных моў у залежнасці ад вашых патрэб і пераваг.','Various interesting settings that can be used in the development of your project.'=>'Розныя цікавыя налады, якія можна выкарыстоўваць пры распрацоўцы вашага праекта.','This setting determines the search mode within the WordPress core depending on the type of language located in the database.'=>'Гэты параметр вызначае рэжым пошуку ў ядры WordPress у залежнасці ад тыпу мовы, якая знаходзіцца ў базе даных.','The search type setting is mostly experimental and you need to test each variant so you can get the best result you need.'=>'Налада тыпу пошуку ў асноўным эксперыментальная, і вам трэба пратэставаць кожны варыянт, каб атрымаць найлепшы вынік.','Arabic'=>'Арабская','Armenian'=>'Армянская','Define whether your primary alphabet on the site is Latin or Cyrillic. If the primary alphabet is Cyrillic then choose Cyrillic. If it is Latin, then choose Latin. This option is crucial for the plugin to work properly.'=>'Вызначце, якая асноўная пісьменнасць выкарыстоўваецца на вашым сайце: лацініца ці кірыліца. Калі асноўны алфавіт — кірыліца, выберыце кірыліцу. Калі лацініца — выберыце лацініцу. Гэты параметр крытычна важны для карэктнай працы плагіна.','Define whether your primary alphabet on the site.'=>'Вызначце, якая асноўная пісьменнасць выкарыстоўваецца на сайце.','Transliteration disabled'=>'Транслітарацыя адключана','Cyrillic to Latin'=>'Кірыліца ў лацініцу','Latin to Cyrillic'=>'Лацініца ў кірыліцу','Arabic to Latin'=>'Арабская ў лацініцу','Latin to Arabic'=>'Лацініца ў арабскую','Armenian to Latin'=>'Армянская ў лацініцу','Latin to Armenian'=>'Лацініца ў армянскую','This option determines the global transliteration of your web site. If you do not want to transliterate the entire website and use this plugin for other purposes, disable this option. This option does not affect to the functionality of short codes and tags.'=>'Гэты параметр вызначае глабальную транслітарацыю вашага сайта. Калі вы не хочаце транслітараваць увесь сайт і выкарыстоўваеце гэты плагін для іншых мэтаў, адключыце гэтую опцыю. Гэтая опцыя не ўплывае на працу шорткодаў і тэгаў.','This option determines the type of language script that the visitors sees when they first time come to your site.'=>'Гэты параметр вызначае, якую пісьменнасць убачаць наведвальнікі пры першым наведванні вашага сайта.','Automatical'=>'Аўтаматычна','This option defines the language script. Automatic script detection is the best way but if you are using a WordPress installation in a language that does not match the scripts supported by this plugin, then choose on which script you want the transliteration to be performed.'=>'Гэты параметр вызначае пісьменнасць мовы. Аўтаматычнае вызначэнне пісьменнасці — найлепшы варыянт, але калі вы выкарыстоўваеце ўсталёўку WordPress на мове, якая не супадае з пісьменнасцямі, што падтрымліваюцца гэтым плагінам, выберыце, для якой пісьменнасці павінна выконвацца транслітарацыя.','This option configures the operating mode of the entire plugin and affects all aspects of the site related to transliteration. Each mode has its own set of filters, which are activated based on your specific needs. It\'s important to take the time to review and customize these settings according to your preferences.'=>'Гэты параметр наладжвае рэжым працы ўсяго плагіна і ўплывае на ўсе аспекты сайта, звязаныя з транслітарацыяй. Кожны рэжым мае ўласны набор фільтраў, якія актывуюцца ў залежнасці ад вашых патрэб. Важна надаць час агляду і наладзе гэтых параметраў у адпаведнасці з вашымі перавагамі.','Forced transliteration can sometimes cause problems if Latin is translated into Cyrillic in pages and posts. To this combination must be approached experimentally.'=>'Прымусовая транслітарацыя часам можа выклікаць праблемы, калі лацініца на старонках і ў запісах перакладаецца ў кірыліцу. Да гэтай камбінацыі трэба падыходзіць эксперыментальна.','Exclude filters you don\'t need (optional)'=>'Выключыце непатрэбныя фільтры (неабавязкова)','Select the transliteration filters you want to exclude.'=>'Выберыце фільтры транслітарацыі, якія хочаце выключыць.','The filters you select here will not be transliterated (these filters do not work on forced transliteration).'=>'Выбраныя тут фільтры не будуць транслітаравацца (гэтыя фільтры не працуюць пры прымусовай транслітарацыі).','TIPS & TRICKS:'=>'ПАРАДЫ І ХІТРАСЦІ:','You can find details about some of the listed filters in this article:'=>'Падрабязнасці пра некаторыя з пералічаных фільтраў вы можаце знайсці ў гэтым артыкуле:','Since you are already a WooCommerce user, you also can see the following documentation: %s'=>'Паколькі вы ўжо карыстаецеся WooCommerce, вы таксама можаце азнаёміцца з наступнай дакументацыяй: %s','Separate words, phrases, names and expressions with the sign %s or put it in a new row. HTML is not allowed.'=>'Раздзяляйце словы, фразы, імёны і выразы знакам %s або размяшчайце іх з новага радка. HTML не дазваляецца.','Yes'=>'Так','No'=>'Не','JavaScript Dynamic Transliteration ensures that all dynamically loaded content is properly transliterated in real time. It processes AJAX, builder-generated, and frontend-rendered elements while preserving HTML structure, URLs, and excluded words. <b>This option is only needed if some content is not transliterated correctly.</b>'=>'Дынамічная транслітарацыя JavaScript гарантуе, што ўвесь дынамічна загружаны кантэнт будзе карэктна транслітаравацца ў рэжыме рэальнага часу. Яна апрацоўвае AJAX, элементы, створаныя канструктарамі, і элементы, адмаляваныя на фронтэндзе, захоўваючы структуру HTML, URL і выключаныя словы. <b>Гэты параметр патрэбны толькі тады, калі частка змесціва транслітаруецца некарэктна.</b>','If you have a problem caching your pages, our plugin solves this problem by clearing the cache when changing the language script.'=>'Калі ў вас узнікаюць праблемы з кэшаваннем старонак, наш плагін вырашае іх, ачышчаючы кэш пры змене пісьменнасці мовы.','This option forces the widget to transliterate. There may be some unusual behaviour in the rare cases.'=>'Гэты параметр прымусова ўключае транслітарацыю віджэта. У рэдкіх выпадках магчыма незвычайнае паводзіны.','Enable this feature if you want to force transliteration of email content.'=>'Уключыце гэтую функцыю, калі хочаце прымусова транслітараваць змесціва электроннай пошты.','Enable this feature if you want to force transliteration of WordPress REST API calls. The WordPress REST API is also used in many AJAX calls, WooCommerce, and page builders. It is recommended to be enabled by default.'=>'Уключыце гэтую функцыю, калі хочаце прымусова транслітараваць выклікі WordPress REST API. WordPress REST API таксама выкарыстоўваецца ў многіх AJAX-запытах, WooCommerce і канструктарах старонак. Рэкамендуецца ўключыць яе па змаўчанні.','Enable this feature if you want to force transliteration of AJAX calls. If you want to avoid transliteration of specific individual AJAX calls, you must add a new POST or GET parameter to your AJAX call: %s'=>'Уключыце гэтую функцыю, калі хочаце прымусова транслітараваць AJAX-запыты. Калі вы хочаце пазбегнуць транслітарацыі асобных AJAX-запытаў, трэба дадаць новы параметр POST або GET у ваш AJAX-запыт: %s','Enable if you want the WP-Admin area to be transliterated.'=>'Уключыце, калі хочаце, каб вобласць WP-Admin транслітаравалася.','Allows to create users with usernames containing Cyrillic characters.'=>'Дазваляе ствараць карыстальнікаў з імёнамі, якія змяшчаюць кірылічныя сімвалы.','This feature enables you to easily transliterate titles and content directly within the WordPress editor. This functionality is available for various content types, including categories, pages, posts, and custom post types, ensuring a seamless experience when managing multilingual content on your site. With just a few clicks, you can switch between scripts, making your content accessible to a broader audience.'=>'Гэта функцыя дазваляе лёгка транслітараваць загалоўкі і змесціва непасрэдна ў рэдактары WordPress. Яна даступная для розных тыпаў змесціва, уключаючы катэгорыі, старонкі, запісы і карыстальніцкія тыпы запісаў, забяспечваючы зручную працу з шматмоўным змесцівам на вашым сайце. Усяго некалькімі клікамі вы можаце пераключацца паміж пісьменнасцямі, робячы змесціва даступным для больш шырокай аўдыторыі.','Enable if you want to force cyrillic permalinks to latin.'=>'Уключыце, калі хочаце прымусова пераўтвараць кірылічныя пастаянныя спасылкі ў лацініцу.','Enable if you want to convert cyrillic filenames to latin.'=>'Уключыце, калі хочаце пераўтвараць кірылічныя імёны файлаў у лацініцу.','hyphen (default)'=>'дэфіс (па змаўчанні)','underscore'=>'ніжняе падкрэсліванне','dot'=>'кропка','tilde'=>'тыльда','vartical bar'=>'вертыкальная рыса','asterisk'=>'зорачка','Filename delimiter, example:'=>'Раздзяляльнік імя файла, прыклад:','my-upload-file.jpg'=>'my-upload-file.jpg','Approve if you want transliteration for the search field.'=>'Уключыце, калі хочаце транслітарацыю для поля пошуку.','Try to fix the diacritics in the search field.'=>'Паспрабаваць выпраўляць дыякрытычныя знакі ў полі пошуку.','Automatical (recommended)'=>'Аўтаматычна (рэкамендуецца)','Based on the plugin mode'=>'На аснове рэжыму плагіна','The search has two working modes. Choose the one that works best with your search.'=>'Пошук мае два рэжымы працы. Выберыце той, які найлепш падыходзіць для вашага пошуку.','(safe)'=>'(бяспечна)','(standard)'=>'(стандартна)','(optional)'=>'(неабавязкова)','This option dictates which URL parameter will be used to change the language.'=>'Гэты параметр вызначае, які параметр URL будзе выкарыстоўвацца для змены мовы.','This option transliterate the RSS feed.'=>'Гэты параметр транслітаруе RSS-стужку.','Transliterate'=>'Транслітараваць','Omit the transliteration'=>'Прапусціць транслітарацыю','This option adds CSS classes to your body HTML tag. These CSS classes vary depending on the language script.'=>'Гэты параметр дадае CSS-класы да вашага HTML-тэга body. Гэтыя CSS-класы залежаць ад пісьменнасці мовы.','Enable Theme Support'=>'Уключыць падтрымку тэмы','Disable Theme Support'=>'Адключыць падтрымку тэмы','If you don\'t require transliteration support for your theme, you can disable it for your current theme here.'=>'Калі вашай тэме не патрэбна падтрымка транслітарацыі, вы можаце адключыць яе для бягучай тэмы тут.','This mode has no filters.'=>'У гэтым рэжыме няма фільтраў.','Transliterator is free to use and actively maintained. Ongoing updates, performance improvements, and new features require continuous time and resources.'=>'Transliterator бясплатны ў выкарыстанні і актыўна падтрымліваецца. Пастаянныя абнаўленні, паляпшэнне прадукцыйнасці і новыя функцыі патрабуюць часу і рэсурсаў.','If the plugin adds value to your work, you are welcome to support its further development with a voluntary contribution.'=>'Калі плагін прыносіць карысць вашай працы, вы можаце падтрымаць яго далейшае развіццё добраахвотным унёскам.','Banca Intesa a.d. Beograd'=>'Banca Intesa a.d. Beograd','Thank you for your support.'=>'Дзякуй за вашу падтрымку.','If you want to support our work and effort, if you have new ideas or want to improve the existing code, %s.'=>'Калі вы хочаце падтрымаць нашу працу і намаганні, калі ў вас ёсць новыя ідэі або вы хочаце палепшыць існуючы код, %s.','join our team'=>'далучайцеся да нашай каманды','Settings saved.'=>'Налады захаваны.','Settings'=>'Налады','Shortcodes'=>'Шорткоды','PHP Functions'=>'PHP-функцыі','5 stars?'=>'5 зорак?','Transliteration Settings'=>'Налады транслітарацыі','To Latin'=>'У лацініцу','To Cyrillic'=>'У кірыліцу','Transliterate:'=>'Транслітараваць:','Loading...'=>'Загрузка...','Please wait! Do not close the window or leave the page until this operation is completed!'=>'Калі ласка, пачакайце! Не закрывайце акно і не пакідайце старонку, пакуль аперацыя не будзе завершана!','DONE!!!'=>'ГОТОВА!!!','PLEASE UPDATE PLUGIN SETTINGS'=>'КАЛІ ЛАСКА, АБНАВІЦЕ НАЛАДЫ ПЛАГІНА','Carefully review the transliteration plugin settings and adjust how it fits your WordPress installation. It is important that every time you change the settings, you test the parts of the site that are affected by this plugin.'=>'Уважліва праверце налады плагіна транслітарацыі і наладзьце іх у адпаведнасці з вашай усталёўкай WordPress. Важна, каб кожны раз пасля змены налад вы правяралі тыя часткі сайта, на якія ўплывае гэты плагін.','Tags'=>'Тэгі','Transliteration Tool'=>'Інструмент транслітарацыі','Permalink Tool'=>'Інструмент пастаянных спасылак','General Settings'=>'Агульныя налады','Documentation'=>'Дакументацыя','Tools'=>'Інструменты','Debug'=>'Адладка','Credits'=>'Падзякі','Support'=>'Падтрымка','Save Changes'=>'Захаваць змены','Available shortcodes'=>'Даступныя шорткоды','Available PHP Functions'=>'Даступныя PHP-функцыі','Available Tags'=>'Даступныя тэгі','Converter for transliterating Cyrillic into Latin and vice versa'=>'Канвертар для транслітарацыі кірыліцы ў лацініцу і наадварот','Permalink Transliteration Tool'=>'Інструмент транслітарацыі пастаянных спасылак','Debug information'=>'Адладкавая інфармацыя','WordPress Transliterator'=>'Транслітаратар WordPress','Quick Access:'=>'Хуткі доступ:','Rate us'=>'Ацаніце нас','Current Settings:'=>'Бягучыя налады:','Transliteration Mode:'=>'Рэжым транслітарацыі:','Cache Support:'=>'Падтрымка кэша:','Media Transliteration:'=>'Транслітарацыя медыя:','Permalink Transliteration:'=>'Транслітарацыя пастаянных спасылак:','Transliterator plugin options are not yet available. Please update plugin settings!'=>'Параметры плагіна Transliterator пакуль недаступныя. Калі ласка, абнавіце налады плагіна!','This plugin is 100% free. If you want to buy us one coffee, beer or in general help the development of this plugin through a monetary donation, you can do it in the following ways:'=>'Гэты плагін на 100% бясплатны. Калі вы хочаце пачаставаць нас кавай, півам або ўвогуле дапамагчы развіццю гэтага плагіна грашовым ахвяраваннем, вы можаце зрабіць гэта наступнымі спосабамі:','From Serbia'=>'З Сербіі','This is a light weight, simple and easy plugin with which you can transliterate your WordPress installation from Cyrillic to Latin and vice versa in a few clicks. This transliteration plugin also supports special shortcodes that you can use to partially transliterate parts of the content.'=>'Гэта лёгкі, просты і зручны плагін, з дапамогай якога вы можаце ў некалькі клікаў транслітараваць вашу ўсталёўку WordPress з кірыліцы ў лацініцу і наадварот. Гэты плагін транслітарацыі таксама падтрымлівае спецыяльныя шорткоды, якія можна выкарыстоўваць для частковай транслітарацыі змесціва.','Sponsors of this plugin:'=>'Спонсары гэтага плагіна:','If you want to help develop this plugin and be one of the sponsors, please contact us at: %s'=>'Калі вы хочаце дапамагчы ў распрацоўцы гэтага плагіна і стаць адным са спонсараў, звяжыцеся з намі па адрасе: %s','Special thanks to the contributors in the development of this plugin:'=>'Асаблівая падзяка ўдзельнікам распрацоўкі гэтага плагіна:','Copyright'=>'Аўтарскія правы','Copyright &copy; 2020 - %1$d %2$s by %3$s. All Right Reserved.'=>'Аўтарскія правы &copy; 2020 - %1$d %2$s, %3$s. Усе правы абаронены.','Transliterator – WordPress Transliteration'=>'Transliterator – транслітарацыя WordPress','This program is free software; you can redistribute it and/or modify it under the terms of the GNU General Public License as published by the Free Software Foundation; either version 2 of the License, or (at your option) any later version.'=>'Гэта праграма з\'яўляецца свабодным праграмным забеспячэннем; вы можаце распаўсюджваць яе і/або змяняць на ўмовах GNU General Public License, апублікаванай Free Software Foundation; альбо версіі 2 ліцэнзіі, альбо (на ваш выбар) любой пазнейшай версіі.','This program is distributed in the hope that it will be useful, but WITHOUT ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.'=>'Гэта праграма распаўсюджваецца ў надзеі, што яна будзе карыснай, але БЕЗ ЯКІХ-НЕБУДЗЬ ГАРАНТЫЙ; нават без неяўнай гарантыі КАМЕРЦЫЙНАЙ ПРЫДАТНАСЦІ або ПРЫДАТНАСЦІ ДЛЯ ПЭЎНАЙ МЭТЫ.','See the GNU General Public License for more details.'=>'Гл. GNU General Public License для атрымання больш падрабязнай інфармацыі.','You should have received a copy of the GNU General Public License along with this program; if not, write to the Free Software Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301, USA.'=>'Вы павінны былі атрымаць копію GNU General Public License разам з гэтай праграмай; калі не, напішыце ў Free Software Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301, USA.','Plugin ID'=>'ID плагіна','Plugin version'=>'Версія плагіна','WordPress version'=>'Версія WordPress','Last plugin update'=>'Апошняе абнаўленне плагіна','PHP version'=>'Версія PHP','PHP version ID'=>'ID версіі PHP','PHP architecture'=>'Архітэктура PHP','%d bit'=>'%d біт','WordPress debug'=>'Адладка WordPress','On'=>'Укл.','Off'=>'Выкл.','WordPress multisite'=>'WordPress multisite','WooCommerce active'=>'WooCommerce актыўны','WooCommerce version'=>'Версія WooCommerce','Site title'=>'Назва сайта','Tagline'=>'Кароткае апісанне','WordPress address (URL)'=>'Адрас WordPress (URL)','Admin email'=>'Email адміністратара','Encoding for pages and feeds'=>'Кадаванне старонак і стужак','Content-Type'=>'Content-Type','Site Language'=>'Мова сайта','Server time'=>'Час сервера','WordPress directory path'=>'Шлях да каталога WordPress','Operting system'=>'Аперацыйная сістэма','User agent'=>'User agent','Plugin directory path'=>'Шлях да каталога плагіна','Plugin settings'=>'Налады плагіна','These are available PHP functions that you can use in your themes and plugins.'=>'Гэта даступныя PHP-функцыі, якія можна выкарыстоўваць у вашых тэмах і плагінах.','Determines whether the site is already in Cyrillic.'=>'Вызначае, ці выкарыстоўвае сайт ужо кірыліцу.','This function provides information on whether the currently active language is excluded from transliteration.'=>'Гэта функцыя паведамляе, ці выключана бягучая актыўная мова з транслітарацыі.','Transliteration of some text or content into the desired script.'=>'Транслітарацыя пэўнага тэксту або змесціва ў патрэбную пісьменнасць.','The <b><i>$type</i></b> parameter has two values: <code>cyr_to_lat</code> (Cyrillic to Latin) and <code>lat_to_cyr</code> (Latin to Cyrillic)'=>'Параметр <b><i>$type</i></b> мае два значэнні: <code>cyr_to_lat</code> (кірыліца ў лацініцу) і <code>lat_to_cyr</code> (лацініца ў кірыліцу)','Transliteration from Cyrillic to Latin.'=>'Транслітарацыя з кірыліцы ў лацініцу.','Transliteration from Latin to Cyrillic.'=>'Транслітарацыя з лацініцы ў кірыліцу.','Transliterates Cyrillic characters to Latin, converting them to their basic ASCII equivalents by removing diacritics.'=>'Транслітаруе кірылічныя сімвалы ў лацініцу, пераўтвараючы іх у базавыя ASCII-адпаведнікі шляхам выдалення дыякрытыкі.','Get active script.'=>'Атрымаць актыўную пісьменнасць.','This function displays a selector for the transliteration script.'=>'Гэта функцыя адлюстроўвае пераключальнік пісьма для транслітарацыі.','Parameters'=>'Параметры','This attribute contains an associative set of parameters for this function:'=>'Гэты атрыбут утрымлівае асацыятыўны набор параметраў для гэтай функцыі:','(string) The type of selector that will be displayed on the site. It can be: %1$s, %2$s, %3$s, %4$s, %5$s or %6$s. Default: %1$s'=>'(string) Тып селектара, які будзе адлюстроўвацца на сайце. Ён можа быць: %1$s, %2$s, %3$s, %4$s, %5$s або %6$s. Па змаўчанні: %1$s','(bool) determines whether it will be displayed through an echo or as a string. Default: %s'=>'(bool) вызначае, ці будзе значэнне выводзіцца праз echo або як радок. Па змаўчанні: %s','(string) Separator to be used when the selector type is %s. Default: %s'=>'(string) Раздзяляльнік, які выкарыстоўваецца, калі тып селектара — %s. Па змаўчанні: %s','(string) Text for Cyrillic link. Default: %s'=>'(string) Тэкст для спасылкі на кірыліцу. Па змаўчанні: %s','(string) Text for Latin link. Default: %s'=>'(string) Тэкст для спасылкі на лацініцу. Па змаўчанні: %s','This tool enables you to convert all existing Cyrillic permalinks in your database to Latin characters.'=>'Гэты інструмент дазваляе пераўтварыць усе існуючыя кірылічныя пастаянныя спасылкі ў вашай базе даных у лацінскія сімвалы.','Warning:'=>'Папярэджанне:','This option is dangerous and can create unexpected problems. Once you run this script, all permalinks in your database will be modified and this can affect on the SEO causing a 404 error.'=>'Гэты параметр небяспечны і можа выклікаць непрадбачаныя праблемы. Пасля запуску гэтага скрыпту ўсе пастаянныя спасылкі ў вашай базе даных будуць зменены, што можа паўплываць на SEO і выклікаць памылку 404.','Before proceeding, consult with your SEO specialist, as you will likely need to resubmit your sitemap and adjust other settings to update the permalinks in search engines.'=>'Перад працягам пракансультуйцеся са спецыялістам па SEO, бо вам, верагодна, спатрэбіцца паўторна адправіць sitemap і скарэктаваць іншыя налады, каб абнавіць пастаянныя спасылкі ў пошукавых сістэмах.','For advanced users, this function can also be executed via WP-CLI using the command'=>'Для дасведчаных карыстальнікаў гэтую функцыю таксама можна выканаць праз WP-CLI з дапамогай каманды','Important: Make sure to %s before running this script.'=>'Важна: абавязкова %s перад запускам гэтага скрыпту.','back up your database'=>'зрабіце рэзервовую копію базы даных','This tool will affect on the following post types: %s'=>'Гэты інструмент паўплывае на наступныя тыпы запісаў: %s','Let\'s do magic'=>'Зробім магію','Are you sure you want this?'=>'Вы ўпэўнены, што хочаце гэтага?','Disclaimer'=>'Адмова ад адказнасці','While this tool is designed to operate safely, there is always a small risk of unpredictable issues.'=>'Хоць гэты інструмент распрацаваны для бяспечнай працы, заўсёды існуе невялікі рызыка непрадказальных праблем.','Note: We do not guarantee that this tool will function correctly on your server. By using it, you assume all risks and responsibilities for any potential issues.'=>'Заўвага: мы не гарантуем, што гэты інструмент будзе карэктна працаваць на вашым серверы. Выкарыстоўваючы яго, вы бераце на сябе ўсе рызыкі і адказнасць за магчымыя праблемы.','Backup your database before using this tool.'=>'Зрабіце рэзервовую копію базы даных перад выкарыстаннем гэтага інструмента.','These are available shortcodes that you can use in your content, visual editors, themes and plugins.'=>'Гэта даступныя шорткоды, якія можна выкарыстоўваць у змесціве, візуальных рэдактарах, тэмах і плагінах.','Skip transliteration'=>'Прапусціць транслітарацыю','Keep this original'=>'Пакінуць гэта без зменаў','(optional) correct HTML code.'=>'(неабавязкова) карэктны HTML-код.','Optional shortcode parameters'=>'Неабавязковыя параметры шорткода','(optional) correct diacritics.'=>'(неабавязкова) выправіць дыякрытычныя знакі.','Add an image depending on the language script'=>'Дадаць выяву ў залежнасці ад пісьменнасці мовы','With this shortcode you can manipulate images and display images in Latin or Cyrillic depending on the setup.'=>'З дапамогай гэтага шорткода вы можаце кіраваць выявамі і адлюстроўваць іх лацініцай або кірыліцай у залежнасці ад налад.','Example'=>'Прыклад','Main shortcode parameters'=>'Асноўныя параметры шорткода','URL (src) as shown in the Latin language'=>'URL (src), які адлюстроўваецца лацініцай','URL (src) as shown in the Cyrillic language'=>'URL (src), які адлюстроўваецца кірыліцай','(optional) URL (src) to the default image if Latin and Cyrillic are unavailable'=>'(неабавязкова) URL (src) выявы па змаўчанні, калі лацініца і кірыліца недаступныя','(optional) title (alt) description of the image for Cyrillic'=>'(неабавязкова) апісанне title (alt) выявы для кірыліцы','(optional) caption description of the image for Cyrillic'=>'(неабавязкова) апісанне подпісу выявы для кірыліцы','(optional) title (alt) description of the image for Latin'=>'(неабавязкова) апісанне title (alt) выявы для лацініцы','(optional) caption description of the image for Latin'=>'(неабавязкова) апісанне подпісу выявы для лацініцы','(optional) title (alt) description of the image if Latin and Cyrillic are unavailable'=>'(неабавязкова) апісанне title (alt) выявы, калі лацініца і кірыліца недаступныя','(optional) caption description of the imag if Latin and Cyrillic are unavailable'=>'(неабавязкова) апісанне подпісу выявы, калі лацініца і кірыліца недаступныя','Shortcode return'=>'Вяртанае значэнне шорткода','HTML image corresponding to the parameters set in this shortcode.'=>'HTML-выява, якая адпавядае параметрам, зададзеным у гэтым шорткодзе.','Language script menu'=>'Меню пісьменнасці мовы','This shortcode displays a selector for the transliteration script.'=>'Гэты шорткод адлюстроўвае пераключальнік пісьма для транслітарацыі.','(string) The type of selector that will be displayed on the site. It can be: "%1$s", "%2$s", "%3$s" or "%4$s"'=>'(string) Тып селектара, які будзе адлюстроўвацца на сайце. Ён можа быць: \\"%1$s\\", \\"%2$s\\", \\"%3$s\\" або \\"%4$s\\"','(string) Text for Cyrillic link. Default: Cyrillic'=>'(string) Тэкст для спасылкі на кірыліцу. Па змаўчанні: Кірыліца','(string) Text for Latin link. Default: Latin'=>'(string) Тэкст для спасылкі на лацініцу. Па змаўчанні: Лацініца','This shortcodes work independently of the plugin settings and can be used anywhere within WordPress pages, posts, taxonomies and widgets (if they support it).'=>'Гэтыя шорткоды працуюць незалежна ад налад плагіна і могуць выкарыстоўвацца дзе заўгодна на старонках, у запісах, таксаноміях і віджэтах WordPress (калі яны гэта падтрымліваюць).','These tags have a special purpose and work separately from short codes and can be used in fields where short codes cannot be used.'=>'Гэтыя тэгі маюць спецыяльнае прызначэнне, працуюць асобна ад шорткодаў і могуць выкарыстоўвацца ў палях, дзе шорткоды выкарыстоўваць нельга.','These tags have no additional settings and can be applied in plugins, themes, widgets and within other short codes.'=>'Гэтыя тэгі не маюць дадатковых налад і могуць прымяняцца ў плагінах, тэмах, віджэтах і ўнутры іншых шорткодаў.','Copy the desired text into one field and press the desired key to convert the text.'=>'Скапіруйце патрэбны тэкст у адно поле і націсніце патрэбную кнопку, каб пераўтварыць тэкст.','Convert to Latin'=>'Пераўтварыць у лацініцу','Convert to Cyrillic'=>'Пераўтварыць у кірыліцу','Reset'=>'Скінуць','The %1$s shortcode has been deprecated as of version %2$s. Please update your content and use the new %3$s shortcode.'=>'Шорткод %1$s састарэў, пачынаючы з версіі %2$s. Калі ласка, абнавіце змесціва і выкарыстоўвайце новы шорткод %3$s.','Transliteration shortcode does not have adequate parameters and translation is not possible. Please check the documentation.'=>'Шорткод транслітарацыі не мае дастатковых параметраў, і пераклад немагчымы. Калі ласка, праверце дакументацыю.','An error occurred while converting. Please refresh the page and try again.'=>'Падчас пераўтварэння адбылася памылка. Калі ласка, абнавіце старонку і паспрабуйце яшчэ раз.','The field is empty.'=>'Поле пустое.','There was a communication problem. Please refresh the page and try again. If this does not solve the problem, contact the author of the plugin.'=>'Узнікла праблема са сувяззю. Калі ласка, абнавіце старонку і паспрабуйце зноў. Калі гэта не вырашыць праблему, звяжыцеся з аўтарам плагіна.','Phantom Mode (ultra fast DOM-based transliteration)'=>'Phantom Mode (звышхуткая транслітарацыя на аснове DOM)','Light mode (basic parts of the site)'=>'Лёгкі рэжым (базавыя часткі сайта)','Standard mode (content, themes, plugins, translations, menu)'=>'Стандартны рэжым (змесціва, тэмы, плагіны, пераклады, меню)','Advanced mode (content, widgets, themes, plugins, translations, menu, permalinks, media)'=>'Пашыраны рэжым (змесціва, віджэты, тэмы, плагіны, пераклады, меню, пастаянныя спасылкі, медыя)','Forced transliteration (everything)'=>'Прымусовая транслітарацыя (усё)','Only WooCommerce (It bypasses all other transliterations and focuses only on WooCommerce)'=>'Толькі WooCommerce (абыходзіць усе астатнія віды транслітарацыі і засяроджваецца толькі на WooCommerce)','Dev Mode (Only for developers and testers)'=>'Рэжым распрацоўніка (толькі для распрацоўнікаў і тэставальнікаў)',' degrees '=>' градусаў ',' divided by '=>' падзяліць на ',' times '=>' памножыць на ',' plus-minus '=>' плюс-мінус ',' square root '=>' квадратны корань ',' infinity '=>' бясконцасць ',' almost equal to '=>' амаль роўна ',' not equal to '=>' не роўна ',' identical to '=>' тоесна ',' less than or equal to '=>' менш або роўна ',' greater than or equal to '=>' больш або роўна ',' left '=>' налева ',' right '=>' направа ',' up '=>' уверх ',' down '=>' уніз ',' left and right '=>' налева і направа ',' up and down '=>' уверх і ўніз ',' care of '=>' на імя ',' estimated '=>' прыблізна ',' ohm '=>' ом ',' female '=>' жаночы ',' male '=>' мужчынскі ',' Copyright '=>' Аўтарскія правы ',' Registered '=>' Зарэгістравана ',' Trademark '=>' Гандлёвая марка ','Option name'=>'Назва параметра','Value'=>'Значэнне','Key'=>'Ключ','Automatic'=>'Аўтаматычна','Disabled'=>'Адключана','Please wait! Do not close the terminal or terminate the script until this operation is completed!'=>'Калі ласка, пачакайце! Не закрывайце тэрмінал і не перарывайце скрыпт, пакуль аперацыя не будзе завершана!','Progress:'=>'Прагрэс:','Updated page ID %1$d, (%2$s) at URL: %3$s'=>'Абноўлена старонка з ID %1$d, (%2$s) па URL: %3$s','%d permalink was successfully transliterated.'=>'%d пастаянная спасылка была паспяхова транслітаравана.' . "\0" . '%d пастаянныя спасылкі былі паспяхова транслітараваны.' . "\0" . '%d пастаянных спасылак былі паспяхова транслітараваны.','No changes to the permalink have been made.'=>'Змен у пастаянную спасылку не ўносілася.','Choose one of the display types: "%1$s", "%2$s", "%3$s", "%4$s", "%5$s" or "%6$s"'=>'Выберыце адзін з тыпаў адлюстравання: \\"%1$s\\", \\"%2$s\\", \\"%3$s\\", \\"%4$s\\", \\"%5$s\\" або \\"%6$s\\"','Transliterator'=>'Transliterator','You do not have sufficient permissions to access this page.'=>'У вас недастаткова правоў для доступу да гэтай старонкі.','Security check failed. Please try again.'=>'Праверка бяспекі не прайшла. Калі ласка, паспрабуйце яшчэ раз.','Transliterator - Network Settings'=>'Transliterator — сеткавыя налады','Select sites where the plugin should run when it is network-activated.'=>'Выберыце сайты, на якіх павінен працаваць плагін, калі ён актываваны ў сетцы.','Enable'=>'Уключыць','Site'=>'Сайт','Domain'=>'Дамен','Path'=>'Шлях','Site #%d'=>'Сайт №%d','Enable Transliterator on site ID %d'=>'Уключыць Transliterator на сайце з ID %d','No sites found.'=>'Сайты не знойдзены.','Save changes'=>'Захаваць змены','Transliterator – Multilingual and Multi-script Text Conversion'=>'Transliterator — шматмоўнае і шматпісьмовае пераўтварэнне тэксту','https://wordpress.org/plugins/serbian-transliteration/'=>'https://wordpress.org/plugins/serbian-transliteration/','Universal WordPress transliteration for multilingual and non-Latin URLs, permalinks, media, search and full site content into SEO-friendly readable text.'=>'Універсальная WordPress транслітарацыя для шматмоўных і нелацінскіх URL-адрасоў, permalink-спасылак, медыя, пошуку і поўнага змесціва сайта ў SEO-аптымізаваны чытэльны тэкст.','Ivijan-Stefan Stipić'=>'Ivijan-Stefan Stipić','https://profiles.wordpress.org/ivijanstefan/'=>'https://profiles.wordpress.org/ivijanstefan/']];
